from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1
import base64
import json
import os
from typing import Any, Dict

storage_client = storage.Client()
firestore_client = firestore.Client()
publisher = pubsub_v1.PublisherClient()

PROJECT_ID = os.environ.get("GCP_PROJECT") or os.environ.get("GOOGLE_CLOUD_PROJECT")
PUBSUB_TOPIC = os.environ.get("PUBSUB_TOPIC", "file-processed")
FIRESTORE_COLLECTION = os.environ.get("FIRESTORE_COLLECTION", "processed_files")


def process_gcs_file(event: Dict[str, Any], context: Any) -> None:
    bucket_name = event["bucket"]
    file_name = event["name"]
    generation = event.get("generation")
    content_type = event.get("contentType")
    time_created = event.get("timeCreated")
    updated = event.get("updated")

    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    content = blob.download_as_bytes()

    metadata = {
        "bucket": bucket_name,
        "name": file_name,
        "generation": generation,
        "content_type": content_type,
        "time_created": time_created,
        "updated": updated,
        "size_bytes": len(content),
    }

    doc_id = _safe_doc_id(bucket_name, file_name, generation)
    firestore_client.collection(FIRESTORE_COLLECTION).document(doc_id).set(
        {
            **metadata,
            "preview_base64": base64.b64encode(content[:1024]).decode("utf-8"),
            "processed": True,
        }
    )

    topic_path = publisher.topic_path(PROJECT_ID, PUBSUB_TOPIC)
    message = {
        "event_id": getattr(context, "event_id", None),
        "event_type": getattr(context, "event_type", None),
        "metadata": metadata,
    }
    publisher.publish(
        topic_path,
        json.dumps(message).encode("utf-8"),
        bucket=bucket_name,
        name=file_name,
    ).result()


def _safe_doc_id(bucket_name: str, file_name: str, generation: Any) -> str:
    raw = f"{bucket_name}:{file_name}:{generation}"
    return base64.urlsafe_b64encode(raw.encode("utf-8")).decode("utf-8").rstrip("=")